const ids = String($env.GHL_LOCATION_IDS || '').split(',').map(s => s.trim()).filter(Boolean);
if (ids.length === 0) throw new Error('GHL_LOCATION_IDS no configurado');
return ids.map(location_id => ({ json: { location_id } }));

// Fetch paginado de oportunidades GHL con rate limiting (80 req/10s)
async function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

const stateRow    = $input.first().json;
const location_id = stateRow.location_id;
const lastSynced  = stateRow.last_synced_at;
const lastCursor  = stateRow.last_cursor;
const apiKey      = $env.GHL_API_KEY;
if (!apiKey) throw new Error('GHL_API_KEY no configurado');

let allOpps    = [];
let nextCursor = lastCursor || null;
let page = 0;
const MAX_PAGES = 200;

while (page < MAX_PAGES) {
  const url = new URL('https://services.leadconnectorhq.com/opportunities/search');
  url.searchParams.set('location_id', location_id);
  url.searchParams.set('limit', '100');
  if (lastSynced && !nextCursor) url.searchParams.set('date', lastSynced);
  if (nextCursor) url.searchParams.set('startAfter', nextCursor);

  let resp;
  let retries = 0;
  while (retries < 5) {
    try {
      resp = await fetch(url.toString(), {
        headers: { 'Authorization': 'Bearer ' + apiKey, 'Version': '2021-07-28' }
      });
      if (resp.status === 429) {
        await sleep(Math.pow(2, retries) * 1000);
        retries++;
        continue;
      }
      break;
    } catch (err) {
      if (retries >= 4) throw err;
      await sleep(Math.pow(2, retries) * 1000);
      retries++;
    }
  }
  if (!resp.ok) throw new Error('GHL API error ' + resp.status + ' opportunities');

  const data = await resp.json();
  const opps = data.opportunities || [];
  allOpps = allOpps.concat(opps);
  nextCursor = data.meta?.startAfter || null;
  if (!nextCursor || opps.length === 0) break;
  page++;
  await sleep(130);
}

return [{ json: { location_id, opportunities: allOpps, next_cursor: nextCursor } }];

const REGEX_GHL_ID      = /^[a-zA-Z0-9_-]{8,50}$/;
const REGEX_LOCATION_ID = /^[a-zA-Z0-9]{10,30}$/;
function cleanStr(val, maxLen) { if (!val) return null; const s = String(val).trim().substring(0, maxLen); return s.length > 0 ? s : null; }
function validateGHLId(val) { if (!val) return null; const s = String(val).trim(); return REGEX_GHL_ID.test(s) ? s : null; }
function parseISODate(val) { if (!val) return null; const ts = Date.parse(String(val)); return isNaN(ts) ? null : new Date(ts).toISOString(); }
function parseFloatSafe(val) { if (val === null || val === undefined || val === '') return null; const n = parseFloat(val); return isNaN(n) ? null : n; }

const { location_id, opportunities, next_cursor } = $input.first().json;
const validStatuses = ['open', 'won', 'lost', 'abandoned'];

const cleaned = opportunities
  .filter(o => REGEX_GHL_ID.test(String(o.id || '').trim()) && REGEX_LOCATION_ID.test(String(o.locationId || '').trim()))
  .map(o => ({
    opportunity_id:      String(o.id).trim(),
    contact_id:          validateGHLId(o.contactId),
    location_id:         String(o.locationId).trim(),
    pipeline_id:         validateGHLId(o.pipelineId),
    pipeline_name:       cleanStr(o.pipelineName, 200),
    pipeline_stage_id:   validateGHLId(o.pipelineStageId),
    stage_name:          cleanStr(o.stageName, 200),
    status:              validStatuses.includes(cleanStr(o.status, 20)) ? cleanStr(o.status, 20) : null,
    monetary_value:      parseFloatSafe(o.monetaryValue) ?? 0,
    currency:            cleanStr(o.currency, 3) || 'COP',
    assigned_to_user_id: validateGHLId(o.assignedTo),
    assigned_to_name:    cleanStr(o.assignedToName, 200),
    custom_fields:       (o.customFields && typeof o.customFields === 'object') ? o.customFields : null,
    close_date:          parseISODate(o.closeDate),
    ghl_created_at:      parseISODate(o.dateAdded  || o.createdAt),
    ghl_updated_at:      parseISODate(o.dateUpdated || o.updatedAt),
    synced_at:           new Date().toISOString()
  })).filter(o => o.contact_id);

return [{ json: { location_id, opportunities: cleaned, next_cursor, total: cleaned.length } }];

const TRACKED = ['pipeline_stage_id', 'status', 'monetary_value', 'assigned_to_user_id', 'pipeline_id'];
const state    = $('Sanitizar Batch Oportunidades').first().json;
const existing = $input.first().json;
const now      = new Date().toISOString();

const rows = Array.isArray(existing) ? existing : (existing.data || [existing]);
const existingMap = {};
for (const row of rows) { if (row && row.opportunity_id) existingMap[row.opportunity_id] = row; }

const inserts      = [];
const scdUpdates   = [];
const minorUpdates = [];

for (const inc of state.opportunities) {
  const prev = existingMap[inc.opportunity_id];
  if (!prev) {
    inserts.push(Object.assign({}, inc, { valid_from: now, valid_to: null, is_current: true, change_reason: 'initial_insert' }));
    continue;
  }
  const changed = TRACKED.filter(f => String(prev[f] ?? null) !== String(inc[f] ?? null));
  if (changed.length > 0) {
    scdUpdates.push({ close_surrogate: prev.surrogate_key, close_valid_to: now, record: Object.assign({}, inc, { valid_from: now, valid_to: null, is_current: true, change_reason: changed.map(f => f + '_change').join(', ') }) });
  } else {
    minorUpdates.push({ surrogate_key: prev.surrogate_key, synced_at: now, ghl_updated_at: inc.ghl_updated_at || now, custom_fields: inc.custom_fields });
  }
}
// NOTA: fact_opp_stage_history NO se escribe en polling — solo en WF-02 (webhook)
return [{ json: { inserts, scdUpdates, minorUpdates, location_id: state.location_id, next_cursor: state.next_cursor, total: state.total } }];
